code.snippet:
// ❌ BAD - mutable struct in readonly field; defensive copy silently swallows SetX
struct Price { public decimal Amount; public void SetAmount(decimal v) { Amount = v; } }
class Product { public readonly Price BasePrice = new Price { Amount = 9.99m }; }
var p = new Product();
p.BasePrice.SetAmount(0m); // silently mutates a temp copy - no effect
Console.WriteLine(p.BasePrice.Amount); // 9.99 - not 0

// ✅ GOOD - readonly struct prevents mutation and eliminates defensive copy
readonly struct Price { public readonly decimal Amount; public Price(decimal a) { Amount = a; } }
class Product { public readonly Price BasePrice = new Price(9.99m); }
// BasePrice.SetAmount(0m) would not exist - readonly struct enforces immutability at compile time

