code.snippet:
// ❌ BAD - mutable struct behind an interface; invisible boxing causes confusion
struct CartItem : IPriceable { public decimal Price; public void SetPrice(decimal p) { Price = p; } }
IPriceable item = new CartItem { Price = 10m }; // boxes
item.SetPrice(20m); // mutates the box
CartItem original = new CartItem { Price = 10m };
IPriceable itemRef = original; // boxes a copy
itemRef.SetPrice(20m); // box is 20 now
Console.WriteLine(original.Price); // 10 - original unchanged

// ✅ GOOD - use class for mutable objects behind interfaces
class CartItem : IPriceable { public decimal Price; public void SetPrice(decimal p) { Price = p; } }

