code.snippet:
// ❌ BAD - trying to mutate struct elements in foreach (compile error)
struct Product { public decimal Price; }
var cart = new List<Product> { new Product { Price = 10m }, new Product { Price = 20m } };
foreach (var item in cart)
    item.Price *= 1.2m; // CS1654 - cannot assign to foreach variable

// ✅ GOOD - use indexed for loop
for (int i = 0; i < cart.Count; i++)
{
    var item = cart[i];
    item.Price *= 1.2m;
    cart[i] = item;
}
